<script setup lang="ts">
import{computed,onMounted,ref}from'vue'
import{api}from'../api/client'
import{useAuthStore}from'../stores/auth'
const auth=useAuthStore(),assignments=ref<any[]>([]),courses=ref<any[]>([]),selected=ref<any>(),submissions=ref<any[]>([]),selectedSubmission=ref<any>(),answers=ref<Record<number,string>>({}),tab=ref('list'),error=ref(''),message=ref(''),loading=ref(false)
const isTeacher=computed(()=>['teacher','admin'].includes(auth.user?.role||''))
const groupedAssignments=computed(()=>Object.values(assignments.value.reduce((groups:any,item:any)=>{const key=item.course_id;if(!groups[key])groups[key]={course_id:key,course_name:item.course_name,items:[]};groups[key].items.push(item);return groups},{})) as any[])
const assignmentForm=ref({course_id:0,title:'',description:'',due_at:''})
const questionForm=ref({question_type:'single_choice',stem:'',standard_answer:'',options_text:'A|选项A\nB|选项B',max_score:5})
async function load(){assignments.value=(await api.get('/assignments')).data;courses.value=(await api.get('/courses')).data;if(!assignmentForm.value.course_id&&courses.value.length)assignmentForm.value.course_id=courses.value[0].id}
async function createAssignment(){loading.value=true;try{const payload={...assignmentForm.value,due_at:assignmentForm.value.due_at||null};const data=(await api.post('/assignments',payload)).data;message.value='作业草稿创建成功，请添加题目';await load();await openAssignment(data.id);tab.value='detail'}catch(e:any){error.value=e.message}finally{loading.value=false}}
async function openAssignment(id:number){loading.value=true;try{selected.value=(await api.get(`/assignments/${id}`)).data;answers.value={};if(isTeacher.value)submissions.value=(await api.get(`/assignments/${id}/submissions`)).data;tab.value='detail'}catch(e:any){error.value=e.message}finally{loading.value=false}}
function parseOptions(){if(!['single_choice','multiple_choice'].includes(questionForm.value.question_type))return null;return questionForm.value.options_text.split('\n').filter(Boolean).map(line=>{const [key,...rest]=line.split('|');return{key:key.trim(),content:rest.join('|').trim()}})}
async function addQuestion(){if(!selected.value)return;loading.value=true;try{await api.post(`/assignments/${selected.value.id}/questions`,{question_type:questionForm.value.question_type,stem:questionForm.value.stem,standard_answer:questionForm.value.standard_answer,options:parseOptions(),max_score:questionForm.value.max_score});questionForm.value.stem='';questionForm.value.standard_answer='';message.value='题目添加成功';await openAssignment(selected.value.id)}catch(e:any){error.value=e.message}finally{loading.value=false}}
async function publish(){try{await api.post(`/assignments/${selected.value.id}/publish`);message.value='作业已发布，学生现在可以填写';await openAssignment(selected.value.id);await load()}catch(e:any){error.value=e.message}}
async function submit(){loading.value=true;try{await api.post(`/assignments/${selected.value.id}/submissions`,{answers:selected.value.questions.map((q:any)=>({question_id:q.id,answer:answers.value[q.id]||''}))});message.value='作业提交成功';await openAssignment(selected.value.id);await load()}catch(e:any){error.value=e.message}finally{loading.value=false}}
async function openSubmission(id:number){try{selectedSubmission.value=(await api.get(`/submissions/${id}`)).data}catch(e:any){error.value=e.message}}
async function grade(id:number){loading.value=true;try{await api.post(`/submissions/${id}/grade`);message.value='AI 辅助批改完成，请逐题复核'}catch(e:any){if(!e.message.includes('已经生成'))error.value=e.message}finally{await openSubmission(id);loading.value=false}}
async function review(result:any){try{await api.patch(`/grading-results/${result.id}/review`,{final_score:Number(result.final_score??result.suggested_score),feedback:result.feedback});message.value='该题复核完成';await openSubmission(selectedSubmission.value.id);submissions.value=(await api.get(`/assignments/${selected.value.id}/submissions`)).data}catch(e:any){error.value=e.message}}
function optionLabel(option:any){return option.key||option.option_key}
onMounted(()=>load().catch(e=>error.value=e.message))
</script>
<template><div class="page"><div class="page-title"><div><h1>{{isTeacher?'作业管理中心':'我的作业'}}</h1><p>{{isTeacher?'创建、发布作业，查看提交并完成 AI 辅助批改。':'查看老师布置的作业，在线填写并跟踪批改状态。'}}</p></div><button v-if="isTeacher" @click="tab=tab==='create'?'list':'create'">{{tab==='create'?'返回列表':'＋ 创建作业'}}</button></div><div class="notice error" v-if="error">{{error}} <button class="text-button" @click="error=''">关闭</button></div><div class="notice success-box" v-if="message">{{message}} <button class="text-button" @click="message=''">关闭</button></div><div v-if="tab==='create'&&isTeacher" class="card"><h2>创建作业草稿</h2><div class="form-grid"><label>发布课程<select v-model.number="assignmentForm.course_id"><option v-for="c in courses" :value="c.id">{{c.name}}</option></select></label><label>作业标题<input v-model="assignmentForm.title" placeholder="例如：第三章课后练习"></label><label>截止时间<input type="datetime-local" v-model="assignmentForm.due_at"></label></div><label>作业说明<textarea v-model="assignmentForm.description" placeholder="填写作业要求和注意事项"/></label><button :disabled="loading" @click="createAssignment">创建并添加题目</button></div><div v-if="tab==='list'"><div v-if="!assignments.length" class="card empty">暂无作业</div><section v-for="group in groupedAssignments" :key="group.course_id" class="card assignment-group"><div class="section-header"><div><span class="eyebrow">课程作业</span><h2>{{group.course_name}}</h2></div><span class="badge">{{group.items.length}} 项</span></div><div class="assignment-list"><article v-for="a in group.items" :key="a.id" class="assignment-card" @click="openAssignment(a.id)"><div class="assignment-state"><span :class="['status',a.status]">{{a.status}}</span><span v-if="a.my_submission" class="status submitted">已提交</span></div><h3>{{a.title}}</h3><p>{{a.description||'暂无作业说明'}}</p><div class="assignment-meta"><span>总分：{{a.total_score}}</span><span>题目：{{a.question_count}}</span><span v-if="isTeacher">提交：{{a.submission_count}}</span><span>截止：{{a.due_at?new Date(a.due_at).toLocaleString():'不限'}}</span></div><button class="secondary">查看作业</button></article></div></section></div><div v-if="tab==='detail'&&selected" class="detail-layout"><div class="card"><button class="back" @click="tab='list';selected=null">← 返回作业列表</button><div class="section-header"><div><span class="eyebrow">{{selected.course_name}}</span><h2>{{selected.title}}</h2><p>{{selected.description}}</p></div><span :class="['status',selected.status]">{{selected.status}}</span></div><div class="assignment-meta"><span>总分 {{selected.total_score}}</span><span>{{selected.question_count}} 道题</span><span>截止 {{selected.due_at?new Date(selected.due_at).toLocaleString():'不限'}}</span></div><div class="question" v-for="(q,index) in selected.questions" :key="q.id"><div class="question-title"><strong>{{index+1}}. {{q.stem}}</strong><span>{{q.max_score}} 分</span></div><div v-if="q.options?.length" class="options"><label v-for="o in q.options"><input :type="q.question_type==='multiple_choice'?'checkbox':'radio'" :name="`q${q.id}`" :value="optionLabel(o)" v-model="answers[q.id]">{{optionLabel(o)}}. {{o.content}}</label></div><textarea v-else-if="!isTeacher&&!selected.my_submission" v-model="answers[q.id]" placeholder="请输入答案"></textarea><div v-if="isTeacher" class="answer-key"><span>参考答案：{{q.standard_answer}}</span></div></div><template v-if="isTeacher"><div class="teacher-actions"><button v-if="selected.status==='draft'&&selected.questions.length" @click="publish">发布作业</button></div><div v-if="selected.status==='draft'" class="question-builder"><h3>添加题目</h3><div class="form-grid"><label>题型<select v-model="questionForm.question_type"><option value="single_choice">单选题</option><option value="multiple_choice">多选题</option><option value="true_false">判断题</option><option value="short_answer">简答题</option><option value="essay">论述题</option></select></label><label>满分<input type="number" min="1" v-model.number="questionForm.max_score"></label></div><label>题干<textarea v-model="questionForm.stem"></textarea></label><label v-if="['single_choice','multiple_choice'].includes(questionForm.question_type)">选项（每行：编号|内容）<textarea v-model="questionForm.options_text"></textarea></label><label>参考答案<textarea v-model="questionForm.standard_answer"></textarea></label><button @click="addQuestion">添加题目</button></div></template><button v-else-if="selected.status==='published'&&!selected.my_submission" :disabled="loading" @click="submit">提交作业</button><div v-else-if="selected.my_submission" class="submitted-panel">已于 {{new Date(selected.my_submission.submitted_at).toLocaleString()}} 提交，状态：{{selected.my_submission.status}}<button class="secondary" @click="openSubmission(selected.my_submission.id)">查看结果</button></div></div><aside v-if="isTeacher" class="card submission-panel"><h2>学生提交 <span class="badge">{{submissions.length}}</span></h2><div v-if="!submissions.length" class="empty">暂无学生提交</div><button v-for="s in submissions" :key="s.id" class="submission-item" @click="openSubmission(s.id)"><span><strong>{{s.student_name}}</strong><small>{{new Date(s.submitted_at).toLocaleString()}}</small></span><span :class="['status',s.status]">{{s.status}}</span></button></aside></div><div v-if="selectedSubmission" class="modal-backdrop" @click.self="selectedSubmission=null"><div class="modal"><button class="modal-close" @click="selectedSubmission=null">×</button><h2>提交与批改详情</h2><p>提交编号 #{{selectedSubmission.id}} · 状态 {{selectedSubmission.status}}</p><div v-for="(answer,index) in selectedSubmission.answers" class="review-answer"><strong>第 {{index+1}} 题答案</strong><p>{{answer.answer}}</p><template v-if="selectedSubmission.grading_results.find((r:any)=>r.question_id===answer.question_id)"><div v-for="r in selectedSubmission.grading_results.filter((r:any)=>r.question_id===answer.question_id)" class="grading-box"><label>最终得分<input type="number" v-model.number="r.final_score" :placeholder="String(r.suggested_score)"></label><label>评语<textarea v-model="r.feedback"></textarea></label><span>AI 建议分：{{r.suggested_score}} · 置信度：{{r.confidence}}</span><button v-if="isTeacher&&r.status!=='approved'" @click="review(r)">确认该题评分</button></div></template></div><button v-if="isTeacher&&!selectedSubmission.grading_results.length" :disabled="loading" @click="grade(selectedSubmission.id)">启动 AI 辅助批改</button></div></div></div></template>
